/**
 * LoginPage Component
 *
 * ログインページ。
 * LoginFormコンポーネントを統合し、ログイン成功時にダッシュボードへリダイレクトします。
 *
 * ルート: /login
 */

import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import LoginForm from '../components/LoginForm';

/**
 * LoginPageコンポーネント
 * ログインフォームとレイアウトを提供します
 */
const LoginPage: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();

  /**
   * ログイン成功時のハンドラー
   * セッション切れ後のリダイレクトがある場合は元のURLへ戻る（FR-005）
   */
  const handleLoginSuccess = () => {
    // React Router の navigate を使用して、basename を尊重したリダイレクトを行う
    const from =
      (location.state as { from?: { pathname?: string } } | null)?.from?.pathname ?? '/dashboard';
    navigate(from, { replace: true });
  };

  /**
   * 一時パスワードチャレンジ時のハンドラー
   */
  const handlePasswordChangeRequired = (email: string, session: string) => {
    navigate('/complete-new-password', { state: { email, session } });
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        {/* Logo / Title */}
        <h1 className="text-center text-3xl font-bold text-gray-900">User Auth System</h1>
        <h2 className="mt-6 text-center text-2xl font-semibold text-gray-700">
          Sign in to your account
        </h2>
        {/* Self-registration disabled - admin-managed user system */}
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-lg sm:rounded-lg sm:px-10">
          {/* Login Form */}
          <LoginForm
            onSuccess={handleLoginSuccess}
            onPasswordChangeRequired={handlePasswordChangeRequired}
          />
        </div>
      </div>

      {/* Footer */}
      <div className="mt-8 text-center">
        <p className="text-xs text-gray-500">&copy; 2025 User Auth System. All rights reserved.</p>
      </div>
    </div>
  );
};

export default LoginPage;
