/**
 * LoginForm Component
 *
 * ログインフォームコンポーネント。
 * メールアドレスとパスワードの入力、バリデーション、送信処理を提供します。
 *
 * 使用例:
 * ```tsx
 * <LoginForm onSuccess={() => navigate('/dashboard')} />
 * ```
 */

import React, { useState } from 'react';
import InputField from './InputField';
import Button from './Button';
import ErrorMessage from './ErrorMessage';
import { validateLoginForm } from '../utils/validation';
import { handleNetworkError } from '../utils/errors';
import type { LoginFormData } from '../types';
import { useAuth } from '../hooks/useAuth';

export interface LoginFormProps {
  /** ログイン成功時のコールバック */
  onSuccess?: () => void;
  /** パスワード変更が必要なときのコールバック */
  onPasswordChangeRequired?: (email: string, session: string) => void;
  /** ログイン失敗時のコールバック */
  onError?: (error: string) => void;
}

/**
 * LoginFormコンポーネント
 * ログインフォームを提供します
 */
const LoginForm: React.FC<LoginFormProps> = ({ onSuccess, onPasswordChangeRequired, onError }) => {
  const { login } = useAuth();
  const [formData, setFormData] = useState<LoginFormData>({
    email: '',
    password: '',
    rememberMe: false,
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  /**
   * 入力値変更ハンドラー
   */
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
    // エラーをクリア
    if (errors[name]) {
      setErrors((prev) => ({ ...prev, [name]: '' }));
    }
    setSubmitError(null);
  };

  /**
   * フォーム送信ハンドラー
   */
  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setSubmitError(null);

    // バリデーション
    const validationErrors = validateLoginForm(formData);
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    setIsSubmitting(true);

    try {
      // useAuth 経由でログイン
      const result = await login(formData.email, formData.password);

      // 一時パスワードによるチャレンジ: パスワード変更画面へ
      if (result.challengeName === 'NEW_PASSWORD_REQUIRED' && result.session) {
        if (onPasswordChangeRequired) {
          onPasswordChangeRequired(formData.email, result.session);
        }
        return;
      }

      // 通常ログイン成功時のコールバック
      if (onSuccess) {
        onSuccess();
      }
    } catch (error) {
      // エラーメッセージを取得
      const errorMessage = handleNetworkError(error);
      setSubmitError(errorMessage);

      // エラーコールバック
      if (onError) {
        onError(errorMessage);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4" noValidate>
      {/* Submit Error Message */}
      {submitError && <ErrorMessage message={submitError} variant="error" />}

      {/* Email Field */}
      <InputField
        type="email"
        name="email"
        label="Email Address"
        value={formData.email}
        onChange={handleChange}
        error={errors.email}
        placeholder="you@example.com"
        required
        autoComplete="email"
        disabled={isSubmitting}
      />

      {/* Password Field */}
      <InputField
        type="password"
        name="password"
        label="Password"
        value={formData.password}
        onChange={handleChange}
        error={errors.password}
        placeholder="Enter your password"
        required
        autoComplete="current-password"
        disabled={isSubmitting}
      />

      {/* Remember Me Checkbox */}
      <div className="flex items-center">
        <input
          type="checkbox"
          name="rememberMe"
          id="rememberMe"
          checked={formData.rememberMe}
          onChange={handleChange}
          disabled={isSubmitting}
          className="h-4 w-4 text-primary-600 focus:ring-primary-500 border-gray-300 rounded"
        />
        <label htmlFor="rememberMe" className="ml-2 block text-sm text-gray-700">
          Remember me
        </label>
      </div>

      {/* Submit Button */}
      <Button
        type="submit"
        variant="primary"
        fullWidth
        loading={isSubmitting}
        disabled={isSubmitting}
      >
        {isSubmitting ? 'Logging in...' : 'Login'}
      </Button>
    </form>
  );
};

export default LoginForm;
